157	    }
158	    //#endregion Public API
159	
160	    //#region Private
161	    /**
162	     * @ch 依 Symbol 切 skin（M1~M9）
163	     * EH-2：Symbol 不在範圍 → warn + 不切
164	     */
165	    private SetSkinBySymbol( symbolId: Symbol ): void {
166	        if ( !this.m_spine ) {
167	            warn( '[WantedPosterItem] SetSkinBySymbol: m_spine 未設置' );
168	            return;
169	        }
170	        const skinName = GetSkinNameBySymbol( symbolId );
171	        if ( !skinName ) {
