57	    /**
58	     * @ch 對「一組同 BaseSymbol 的懸賞」執行 ①Mark → ②Symbol_In → ③(Mark_Active ∥ Symbol_Active) → ④底板SET
59	     *
60	     * 透過 WANTED_POSTER_MANAGER_EVENT 與常駐 WantedPosterManager 溝通；
61	     * 場上 Wanted Spine 由 EffectPlate.SpawnAndPlayWantedSymbolIn / PlayWantedSymbolActiveAndRecycle 直接呼叫
62	     *
63	     * 合併語意：同組所有 bounty 共用同一 BaseSymbol（前提②）與同一組位置
64	     * （同 BaseSymbol → awardDataVec 對應唯一一筆 award），故 spawn 只跑一次。
65	     *
66	     * BC-4：對該 BaseSymbol 的所有常駐 item 同時播 Mark → Mark_Active，最後各自 active=false（Manager.OnEvent 內處理）
67	     * BC-6：階段 ③ Mark_Active 與 Symbol_Active 同 Promise.all 起播
68	     * BC-7：場上 spine 顯示組內 Multiple 連乘（純表演）
69	     * 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本方法不再消除，只播 spine 演出。
70	     * EH-1：找不到對應 item 由 Manager 內部 warn + 立刻 resolve，不阻斷流程
71	     */
72	    private async PlayBountyGroupPerform(
73	        group: protocol.ar2pq9Proto.IBountyData[],
74	        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
75	        curPlateSymbol: protocol.ar2pq9Proto.IColumn[],
76	        basePlateIndexes: protocol.ar2pq9Proto.IIntAry[]
77	    ): Promise<void>
78	    {
79	        if ( group.length === 0 ) return;
80	
81	        // 組內共同 BaseSymbol（前提②：同 BaseSymbol 的 BountySymbol 一定相同）
82	        const baseSymbol = group[ 0 ].BaseSymbol;
83	        if ( baseSymbol === null || baseSymbol === undefined )
84	        {
85	            warn( '[WantedPosterState] PlayBountyGroupPerform: BaseSymbol 為空，跳過' );
86	            return;
87	        }
88	
89	        // 位置由組內共同 BaseSymbol 單次取得（與組內筆數無關）
90	        const matchedAward = awardDataVec.find(
91	            award => award.Symbol === baseSymbol
92	                && award.EliminatePos
93	                && award.EliminatePos.length > 0
94	        );
95	        if ( !matchedAward ) return;
96	
97	        // 過濾掉 Wild 位置（spine 與 ④底板只跑非 wild；wild 的消除/底板已在 ExplodeState 處理）
98	        const filteredPositions = this.FilterNonWildPositions(
99	            matchedAward.EliminatePos!, curPlateSymbol
100	        );
101	        // 無非 wild 位置 → 無 spine 可演（wild 消除已在 ExplodeState 完成）
102	        if ( filteredPositions.length === 0 ) return;
103	
104	        // 場上 spine 顯示倍率 = 組內 Multiple 連乘（純表演）
105	        const multiplier = this.ComputeGroupMultiplier( group );
106	
107	        // 把 positions(一維索引) 轉為世界座標（事件 payload 用世界座標，避免在 manager 跨越 SlotReels 依賴）
108	        const worldPositions = filteredPositions.map( pos => {
109	            const col = Math.floor( pos / Game_Define.ROW );
110	            const row = pos % Game_Define.ROW;
111	            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( col, row );
112	        } );
113	
114	        // ① Mark — 事件 + Promise wrapper（同 EffectPlate 對 MULTIPLIER_BASE_MANAGER 的風格）
115	        await new Promise<void>( resolve => {
116	            eventManager.Dispatch(
117	                WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
118	                baseSymbol,
119	                resolve
120	            );
121	        } );
122	
123	        // ② 懸賞令 spine 進場（Symbol_In）。symbol/wild 消除已在 ExplodeState 步驟①完成，此處不再消除
124	        const spawnedNodes: Node[] = await this.m_gameView.EffectPlate.SpawnAndPlayWantedSymbolIn(
125	            worldPositions, baseSymbol, multiplier
126	        );
127	
128	        // ③ Mark_Active ∥ Symbol_Active 同時起播
129	        await Promise.all( [
130	            new Promise<void>( resolve => {
131	                eventManager.Dispatch(
132	                    WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
133	                    baseSymbol,
134	                    resolve
135	                );
136	            } ),
137	            this.m_gameView.EffectPlate.PlayWantedSymbolActiveAndRecycle( spawnedNodes ),
138	        ] );
139	
140	        // ④ 場上 Wanted 表演完成後，更新懸賞令位置的乘倍底板（帶 Spine 動畫）
141	        // 移到組末才升底板，避免被階段②/③的 Spine 動畫分散視覺焦點
142	        await Define.Wait( this.m_gameView, 0.5 );
143	        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true );
144	        const upgradePromises: Promise<void>[] = [];
145	        for ( const pos of filteredPositions )
146	        {
147	            const col = Math.floor( pos / Game_Define.ROW );
148	            const row = pos % Game_Define.ROW;
149	            upgradePromises.push( new Promise<void>( resolve =>
150	            {
151	                eventManager.Dispatch(
152	                    MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM,
153	                    pos,
154	                    basePlateIndexes[ col ].Data[ row ],
155	                    resolve
156	                );
157	            } ) );
158	        }
159	        await Promise.all( upgradePromises );
160	    }
