162	    /**
163	     * @ch BC-1：將已觸發的 bounty 以 BaseSymbol 分組
164	     * 同 BaseSymbol 歸同組；組順序依各 BaseSymbol 首次出現順序，組內保留原順序。
165	     * 輸入契約：吃 FindTriggeredBounties 的輸出（已觸發子集），非原始 bountyDataVec。
166	     */
167	    private GroupBountiesByBaseSymbol(
168	        bounties: protocol.ar2pq9Proto.IBountyData[]
169	    ): protocol.ar2pq9Proto.IBountyData[][]
170	    {
171	        const groups: protocol.ar2pq9Proto.IBountyData[][] = [];
172	        const groupIndexByBaseSymbol = new Map<number, number>();
173	        for ( const bounty of bounties )
174	        {
175	            const key = bounty.BaseSymbol;
176	            if ( key === null || key === undefined ) continue;
177	            const existing = groupIndexByBaseSymbol.get( key );
178	            if ( existing !== undefined )
179	            {
180	                groups[ existing ].push( bounty );
181	            }
182	            else
183	            {
184	                groupIndexByBaseSymbol.set( key, groups.length );
185	                groups.push( [ bounty ] );
186	            }
187	        }
188	        return groups;
189	    }
190	
191	    /**
192	     * @ch BC-2：組內 Multiple 連乘（純函式）
193	     * DR-9：Multiple 為 null/undefined/非有限數 → 視為中性值 1（跳過不計），避免連乘塌成 0。
194	     * 空組回 1。
195	     */
196	    private ComputeGroupMultiplier(
197	        group: protocol.ar2pq9Proto.IBountyData[]
198	    ): number
199	    {
200	        let product = 1;
201	        for ( const bounty of group )
202	        {
203	            const m = bounty.Multiple;
204	            if ( m !== null && m !== undefined && Number.isFinite( m ) )
205	            {
206	                product *= m;
207	            }
208	        }
209	        return product;
210	    }
211	
212	    /**
213	     * @ch 找出被消除的符號中命中懸賞令的資料
214	     * BC-3：EliminatePos.length > 0 代表該符號有被消除；
215	     *       若其 Symbol 值等於某懸賞令的 BaseSymbol，則該懸賞令被觸發。
216	     * R-4：award.Symbol / bounty.BaseSymbol 在 proto 是 number|null，過濾掉 null/undefined 避免污染 Set
217	     */
218	    private FindTriggeredBounties(
219	        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
220	        bountyDataVec: protocol.ar2pq9Proto.IBountyData[]
221	    ): protocol.ar2pq9Proto.IBountyData[]
222	    {
223	        if ( awardDataVec.length === 0 || bountyDataVec.length === 0 )
224	        {
225	            return [];
226	        }
227	
228	        // 收集本次被消除的符號 ID
229	        const eliminatedSymbols = new Set<number>();
230	        for ( const award of awardDataVec )
231	        {
232	            if ( award.EliminatePos && award.EliminatePos.length > 0
233	                && award.Symbol !== null && award.Symbol !== undefined )
234	            {
235	                eliminatedSymbols.add( award.Symbol );
236	            }
237	        }
238	
239	        // 比對懸賞令的 BaseSymbol
240	        return bountyDataVec.filter( bounty =>
241	            bounty.BaseSymbol !== null && bounty.BaseSymbol !== undefined
242	            && eliminatedSymbols.has( bounty.BaseSymbol )
243	        );
244	    }
245	
246	    /**
247	     * @ch 過濾掉 Wild 位置，只保留實際為 BaseSymbol 的位置
248	     */
249	    private FilterNonWildPositions(
250	        positions: number[],
251	        curPlateSymbol: protocol.ar2pq9Proto.IColumn[]
252	    ): number[]
253	    {
254	        return positions.filter( pos =>
255	        {
256	            const col = Math.floor( pos / Game_Define.ROW );
257	            const row = pos % Game_Define.ROW;
258	            const sym = curPlateSymbol?.[ col ]?.Col?.[ row ] ?? -1;
259	            return sym !== Game_Define.Symbol.Wild;
260	        } );
261	    }
262	
263	}
