25	
26	        // 回歸守衛：本盤消除後（Explode②ADD + WantedPoster④SET 已全部完成），
27	        // 被消除位置的乘倍底板 index 應等於 Server 的 BasePlateIndex。不一致只 log，不影響流程。
28	        const playedPlate = curRoundInfo.PlateQueue[ curPlateIndex ];
