43	            return;
44	        }
45	
46	        let plateInfo = curRoundInfo.PlateQueue[ curPlateIndex ];
47	        const nextPlateInfo = curRoundInfo.PlateQueue[ curPlateIndex + 1 ];
48	        let nextPlateSymbols = nextPlateInfo.PlateSymbol;
49	        let eliminatePos = plateInfo.EliminatePos;
50	
51	        // 設置懸賞令資料（cascade → isNewRound=false，附「盤面扣除被消除位置」可見的 BaseSymbol 供持續判斷）
52	        const bountyDataVec = nextPlateInfo.BountyDataVec ? nextPlateInfo.BountyDataVec : [];
