54	        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, bountyDataVec, false, visibleBaseSymbols);
55	        
56	        let fillSymbols: number[][] = [];
57	        let eliminateSymbols: number[][] = [];
58	        if ( eliminatePos )
59	        {
60	            fillSymbols.length = Game_Define.COL;
61	            eliminateSymbols.length = Game_Define.COL;
62	            for ( let col = 0; col < Game_Define.COL; col++ )
63	            {
64	                eliminateSymbols[col] = [];
65	                fillSymbols[col] = [];
66	            }
67	            for ( let i = 0; i < eliminatePos.length; i++ )
68	            {
69	                const { col, row } = this.m_gameView.SlotReels.GetColRowFromPosition(eliminatePos[i]);
70	                
71	                eliminateSymbols[col].push( row );
72	            }
73	            for( let col = 0; col < Game_Define.COL; col++ )
