79	                        
80	                        fillSymbols[col].push( nextPlateSymbols[col].Col[i] );
81	                    }
82	                }
83	            }
84	        }
85	
86	        // 天降
87	        //let fillSymbols = this.m_gameView.ConvertColumn( comboStageInfo.FillSymbols );
88	        //let fillMults = this.m_gameView.ConvertColumn( comboStageInfo.FillMults );
