114	    /**
115	     * @ch 計算「當前 plate 扣除被消除位置」後仍可見的 BaseSymbol 集合
116	     *     供懸賞令判斷同 BaseSymbol 是否仍在玩家盤面上（決定持續或退場再進場）
117	     * @param plateInfo 當前 plate（含 PlateSymbol 與 EliminatePos）
118	     */
119	    private ComputeVisibleBaseSymbols( plateInfo: protocol.ar2pq9Proto.IPlateInfo ): number[]
120	    {
121	        const cols = plateInfo?.PlateSymbol;
122	        if ( !cols ) return [];
123	
124	        // 被消除位置 → "col,row" 字串集合
125	        const eliminated = new Set<string>();
126	        const elim = plateInfo.EliminatePos;
127	        if ( elim )
128	        {
129	            for ( const pos of elim )
130	            {
131	                const { col, row } = this.m_gameView.SlotReels.GetColRowFromPosition( pos );
132	                eliminated.add( `${col},${row}` );
133	            }
134	        }
135	
136	        // 收集所有未被消除位置上的符號
137	        const result = new Set<number>();
138	        for ( let col = 0; col < cols.length; col++ )
139	        {
140	            const colData = cols[ col ]?.Col;
141	            if ( !colData ) continue;
142	            for ( let row = 0; row < colData.length; row++ )
143	            {
144	                if ( eliminated.has( `${col},${row}` ) ) continue;
145	                result.add( colData[ row ] );
146	            }
147	        }
148	        return Array.from( result );
149	    }
